import{_ as e,o as a,c as n,a4 as l}from"./chunks/framework.PZCYvDoh.js";const h=JSON.parse('{"title":"Windows下PX4与Simulink配置教程","description":"","frontmatter":{},"headers":[],"relativePath":"docs/硬件资料/旋翼无人机/Windows下PX4与Simulink配置教程/Windows下PX4与Simulink配置教程.md","filePath":"docs/硬件资料/旋翼无人机/Windows下PX4与Simulink配置教程/Windows下PX4与Simulink配置教程.md"}'),o={name:"docs/硬件资料/旋翼无人机/Windows下PX4与Simulink配置教程/Windows下PX4与Simulink配置教程.md"};function s(i,t,d,c,r,p){return a(),n("div",null,[...t[0]||(t[0]=[l(`<h1 id="windows下px4与simulink配置教程" tabindex="-1">Windows下PX4与Simulink配置教程 <a class="header-anchor" href="#windows下px4与simulink配置教程" aria-label="Permalink to &quot;Windows下PX4与Simulink配置教程&quot;">​</a></h1><h2 id="环境与源码准备-避免网络-tls问题" tabindex="-1">环境与源码准备（避免网络/TLS问题） <a class="header-anchor" href="#环境与源码准备-避免网络-tls问题" aria-label="Permalink to &quot;环境与源码准备（避免网络/TLS问题）&quot;">​</a></h2><ol><li><p><strong>在WSL2 Ubuntu中拉取PX4源码</strong></p><ul><li><p>使用 <code>git clone --recursive</code> 克隆，但国内网络容易遇到 <code>gnutls_handshake</code> 失败。</p></li><li><p><strong>解决方案</strong>：</p><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git config --global http.version HTTP/1.1</span></span>
<span class="line"><span>git config --global --unset http.proxy</span></span>
<span class="line"><span>git config --global --unset https.proxy</span></span></code></pre></div></li><li><p>如果个别子模块（如 <code>nlohmann/json</code>）克隆失败，手动下载zip并解压到对应路径，或改用 <code>git submodule update --force --recursive</code>。</p></li></ul></li><li><p><strong>切换到与MATLAB R2024b兼容的PX4版本</strong></p><ul><li><p>官方要求 v1.14.3，你已从 v1.14.0 升级：</p><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git checkout v1.14.3</span></span>
<span class="line"><span>git submodule update --init --recursive --force</span></span></code></pre></div></li></ul></li></ol><h2 id="解决固件体积超限-flash溢出" tabindex="-1">解决固件体积超限（FLASH溢出） <a class="header-anchor" href="#解决固件体积超限-flash溢出" aria-label="Permalink to &quot;解决固件体积超限（FLASH溢出）&quot;">​</a></h2><p>使用 <code>px4_fmu-v5_multicopter</code> 代替 <code>px4_fmu-v5_default</code>，它去掉了固定翼、UUV、小车等模块，能将固件大小控制在2MB以内。</p><ul><li><strong>在Simulink中修改</strong>： <code>Model Configuration Parameters</code> → <code>Hardware Implementation</code> → <code>Target hardware resources</code> → <code>Build options</code> → <code>CMake configuration</code> → 选择 <code>px4_fmu-v5_multicopter</code>。</li></ul><h2 id="启动脚本-rc-txt-的正确用法" tabindex="-1">启动脚本（rc.txt）的正确用法 <a class="header-anchor" href="#启动脚本-rc-txt-的正确用法" aria-label="Permalink to &quot;启动脚本（rc.txt）的正确用法&quot;">​</a></h2><p><strong>你的目标</strong>：只用Simulink外部模式（Monitor &amp; Tune）通过USB读取数据，不依赖QGC。</p><p><strong>正确配置</strong>（SD卡根目录下的 <code>rc.txt</code>）：</p><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 禁用PX4原生多旋翼控制器（关键！）</span></span>
<span class="line"><span>mc_att_control stop</span></span>
<span class="line"><span>mc_pos_control stop</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 启动基本传感器和估计器</span></span>
<span class="line"><span>sensors start</span></span>
<span class="line"><span>ekf2 start</span></span>
<span class="line"><span>commander start   # 用于解锁/上锁，但不干扰你的控制</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 启动你的Simulink模型</span></span>
<span class="line"><span>px4_simulink_app start</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 注意：不要启动 MAVLink！否则会和外部模式争抢USB端口</span></span></code></pre></div><p><strong>绝对不要</strong>包含 <code>mavlink start -d /dev/ttyACM0</code>，否则Simulink外部模式无法连接。</p><h2 id="simulink模型搭建-读取姿态-位置" tabindex="-1">Simulink模型搭建（读取姿态+位置） <a class="header-anchor" href="#simulink模型搭建-读取姿态-位置" aria-label="Permalink to &quot;Simulink模型搭建（读取姿态+位置）&quot;">​</a></h2><h3 id="正确读取uorb消息-避免总线错误" tabindex="-1">正确读取uORB消息（避免总线错误） <a class="header-anchor" href="#正确读取uorb消息-避免总线错误" aria-label="Permalink to &quot;正确读取uORB消息（避免总线错误）&quot;">​</a></h3><ul><li>使用 <strong>PX4 uORB Read</strong> 模块，设置 <code>Topic name</code>： <ul><li><code>vehicle_attitude</code> → 输出四元数（<code>q[0..3]</code>）或欧拉角</li><li><code>vehicle_local_position</code> → 输出 <code>x, y, z</code>（米）</li></ul></li><li><strong>每个 uORB Read 后面必须紧跟 Bus Selector</strong>，从中勾选你需要的具体信号： <ul><li>例如勾选 <code>q[0]</code> <code>q[1]</code> <code>q[2]</code> <code>q[3]</code></li></ul></li><li>将 Bus Selector 输出的四元数连接到 <strong>Quaternion to Rotation Angles</strong> 模块，得到 roll/pitch/yaw（弧度）。</li><li>用 Gain (180/pi) 转为度数，最后接 <strong>Display</strong> 模块。</li></ul><h3 id="错误案例" tabindex="-1">错误案例 <a class="header-anchor" href="#错误案例" aria-label="Permalink to &quot;错误案例&quot;">​</a></h3><ul><li>直接把 uORB Read 的整个总线连到 Display → 报错“需要非总线信号”</li><li>使用 Bus to Vector 但输入不是虚拟总线 → 报错“不接受非虚拟总线”</li></ul><p><strong>正确连接</strong>： <code>uORB Read</code> → <code>Bus Selector</code>（选具体信号）→ <code>Quaternion to Rotation Angles</code>（可选）→ <code>Display</code>/<code>Scope</code></p><h2 id="simulink配置-求解器与运行模式" tabindex="-1">Simulink配置（求解器与运行模式） <a class="header-anchor" href="#simulink配置-求解器与运行模式" aria-label="Permalink to &quot;Simulink配置（求解器与运行模式）&quot;">​</a></h2><ul><li><strong>求解器</strong>：<code>Fixed-step</code>, <code>discrete (no continuous states)</code>, 步长 <code>0.01</code> (100Hz)</li><li><strong>硬件设置</strong>： <code>Hardware Implementation</code> → <code>Target hardware resources</code> → <code>External mode</code><ul><li>取消勾选 <code>Use the same host serial port...</code></li><li>手动填入串口号（如COM5，Windows设备管理器中查看）</li></ul></li><li><strong>运行模式</strong>： 点击 <strong>Hardware</strong> 选项卡 → <code>Mode: Run on board</code> → <strong>Monitor &amp; Tune</strong><strong>不要</strong>用 <code>Connected I/O</code>（那是临时读取，不会运行你的模型） <strong>不要</strong>用普通绿色“运行”（那是纯电脑仿真）</li></ul><h2 id="常见问题与解决" tabindex="-1">常见问题与解决 <a class="header-anchor" href="#常见问题与解决" aria-label="Permalink to &quot;常见问题与解决&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">现象</th><th style="text-align:left;">原因</th><th style="text-align:left;">解决</th></tr></thead><tbody><tr><td style="text-align:left;"><code>gnutls_handshake()</code> 失败</td><td style="text-align:left;">Git TLS/代理问题</td><td style="text-align:left;">设置 <code>http.version HTTP/1.1</code>，清除代理</td></tr><tr><td style="text-align:left;"><code>FLASH_AXIM overflowed</code></td><td style="text-align:left;">固件太大</td><td style="text-align:left;">使用 <code>px4_fmu-v5_multicopter</code> 配置</td></tr><tr><td style="text-align:left;">QGC能连，但Simulink外部模式连不上</td><td style="text-align:left;"><code>rc.txt</code> 中启动了 MAVLink</td><td style="text-align:left;">注释掉 <code>mavlink start</code></td></tr><tr><td style="text-align:left;">外部模式连接超时</td><td style="text-align:left;">串口号错误或端口被占用</td><td style="text-align:left;">关闭QGC，在设备管理器中确认COM号</td></tr><tr><td style="text-align:left;"><code>Display</code> 报错“需要非总线信号”</td><td style="text-align:left;">直接把总线接到Display</td><td style="text-align:left;">加 <code>Bus Selector</code> 提取标量</td></tr><tr><td style="text-align:left;"><code>Bus to Vector</code> 报错</td><td style="text-align:left;">输入不是虚拟总线</td><td style="text-align:left;">改用 <code>Bus Selector</code> 直接提取信号</td></tr><tr><td style="text-align:left;">编译成功但上电后无数据</td><td style="text-align:left;">SD卡中残留旧 <code>rc.txt</code></td><td style="text-align:left;">删除 <code>rc.txt</code>，只保留你写的新版</td></tr></tbody></table><h2 id="最终成功流程" tabindex="-1">最终成功流程 <a class="header-anchor" href="#最终成功流程" aria-label="Permalink to &quot;最终成功流程&quot;">​</a></h2><ol><li>WSL中拉取PX4 v1.14.3，用 <code>px4_fmu-v5_multicopter</code> 配置。</li><li>SD卡中放入不含MAVLink且禁用原生控制器的 <code>rc.txt</code>。</li><li>Simulink模型中每个 <code>uORB Read</code> 后接 <code>Bus Selector</code> 提取具体信号。</li><li>设置固定步长0.01s，选择 <code>Monitor &amp; Tune</code> 模式，指定正确COM口。</li><li>烧录一次，以后调参可直接在Simulink中改Gain值实时生效。</li></ol>`,24)])])}const g=e(o,[["render",s]]);export{h as __pageData,g as default};
